// n8n Function node
// Accepts: single site object, array of sites, or {competitors:[]}/{data:[]}
// Emits: one item per site with { name, website, domain, socials{...} }

function parseHost(u) {
  if (typeof u !== 'string') return '';
  // strip protocol, credentials, and port, then take host
  const noProto = u.replace(/^\s*/,'').replace(/^https?:\/\//i, '');
  const noCreds = noProto.replace(/^[^/@]+@/, '');
  const host = noCreds.split('/')[0].split('?')[0].split('#')[0];
  return host.replace(/^www\./i, '').toLowerCase();
}

function domainFromUrl(u) {
  const host = parseHost(u);
  // collapse subdomains like m.linkedin.com -> linkedin.com
  const parts = host.split('.').filter(Boolean);
  if (parts.length >= 2) return parts.slice(-2).join('.');
  return host;
}

function pickName(title, website) {
  const host = parseHost(website);
  if (title && typeof title === 'string') {
    let name = title.split(/[|–—-]/)[0].trim();
    name = name.replace(/\b(home|homepage)\b/i, '').trim();
    if (name) return name;
  }
  const base = (host || '').split('.')[0];
  return base ? base.charAt(0).toUpperCase() + base.slice(1) : '';
}

function extractUrlsFromText(text) {
  const out = [];
  const re = /\bhttps?:\/\/[^\s"'<>)]+/gi;
  let m; while ((m = re.exec(text)) !== null) out.push(m[0]);
  return out;
}

function collectAllUrls(site) {
  const urls = new Set();
  if (Array.isArray(site.links)) site.links.forEach(u => { if (typeof u === 'string') urls.add(u); });
  if (Array.isArray(site.articles)) site.articles.forEach(t => {
    if (typeof t === 'string') extractUrlsFromText(t).forEach(u => urls.add(u));
  });
  return Array.from(urls);
}

function normalizeIncoming(items) {
  const sites = [];
  for (const it of (items || [])) {
    let payload = it?.json;
    if (typeof payload === 'string') { try { payload = JSON.parse(payload); } catch {} }
    for (const k of ['body','data']) {
      if (typeof payload?.[k] === 'string') { try { payload[k] = JSON.parse(payload[k]); } catch {} }
    }

    if (Array.isArray(payload)) { payload.forEach(s => s && typeof s === 'object' && sites.push(s)); continue; }
    if (Array.isArray(payload?.competitors)) { payload.competitors.forEach(s => s && sites.push(s)); continue; }
    if (Array.isArray(payload?.data)) { payload.data.forEach(s => s && sites.push(s)); continue; }
    if (Array.isArray(payload?.body)) { payload.body.forEach(s => s && sites.push(s)); continue; }

    if (payload && typeof payload === 'object') {
      const looksLikeSite = ['url','title','links','articles','images','videos','meta']
        .some(k => Object.prototype.hasOwnProperty.call(payload, k));
      if (looksLikeSite) { sites.push(payload); continue; }
    }
  }
  return sites;
}

// ---- Social detectors (host-based, tolerant paths) ----
function firstByHost(urls, host, pathRegex) {
  for (const u of urls) {
    const h = domainFromUrl(u);
    if (h === host) {
      if (!pathRegex) return u;
      const path = (typeof u === 'string' ? u.split(domainFromUrl(u))[1] : '') || '';
      if (pathRegex.test(u)) return u;
    }
  }
  return undefined;
}

const sites = normalizeIncoming(items);

if (!sites.length) {
  const first = items?.[0]?.json ?? null;
  return [{ json: {
    error: 'No site objects found',
    hint: 'Send a site object, an array of sites, or wrap in {competitors:[...] } / {data:[...]}',
    keys: first && typeof first === 'object' ? Object.keys(first) : typeof first
  }}];
}

const out = [];

for (const site of sites) {
  const website = site.url || site.website || site.homepage || '';
  const domain = domainFromUrl(website);
  const urls = collectAllUrls(site);

  const socials = {};
  // LinkedIn (accept company/showcase/school or anything under linkedin.com)
  socials.linkedin  = firstByHost(urls, 'linkedin.com', /(company|showcase|school|in|@)/i) || firstByHost(urls, 'linkedin.com');
  // X / Twitter
  socials.x         = firstByHost(urls, 'x.com') || firstByHost(urls, 'twitter.com');
  // Instagram
  socials.instagram = firstByHost(urls, 'instagram.com');
  // Facebook
  socials.facebook  = firstByHost(urls, 'facebook.com');
  // TikTok
  socials.tiktok    = firstByHost(urls, 'tiktok.com');
  // YouTube (support channel, user, @handle)
  socials.youtube   = firstByHost(urls, 'youtube.com', /\/(@|channel|user)\b/i) || firstByHost(urls, 'youtu.be');

  // prune empties
  Object.keys(socials).forEach(k => !socials[k] && delete socials[k]);

  out.push({
    json: {
      name: pickName(site.title, website),
      website,
      domain,
      socials
    }
  });
}

return [
  {
    json: {
      top5competitors: out.map(i => i.json)
    }
  }
];

// n8n Function — Generic company profile + social link extractor (category-agnostic)
// Output per page:
// {
//   company,
//   article_url,
//   socials: { by_platform, all },
//   company_profile: {
//     name, website, profile_text, summary_512, key_phrases, offerings_detected, regions_detected
//   },
//   profile_for_llm: { company, website, summary, offerings, regions, socials_present },
//   _debug: { ... }
// }

const inputs = $input.all();

/* ------------------------- helpers (generic) ------------------------- */
const REDIRECT_HOSTS = [
  'l.facebook.com','lm.facebook.com','m.facebook.com',
  'lnkd.in','linkedin.com','t.co','bit.ly','tinyurl.com',
  'linktr.ee','lnk.bio','rb.gy','goo.gl','ow.ly'
];

function asArray(x){ return Array.isArray(x) ? x : (x == null ? [] : [x]); }
function uniq(a){ return [...new Set(a.filter(Boolean))]; }

function ensureHttp(u){
  if(!u) return '';
  let s = String(u).trim();
  s = s.replace(/^[<('"`]+|[>)"'`,.]+$/g,'');  // drop stray punct
  if(s.startsWith('//')) s = 'https:' + s;
  if(!/^https?:\/\//i.test(s)) s = 'https://' + s;
  return s;
}

function safeURL(u){ try{ return new URL(u); } catch { return null; } }

function firstQueryParam(url, keys=['u','url','to','dest','destination']){
  for(const k of keys){ const v = url.searchParams.get(k); if(v) return v; }
  return null;
}

function unwrapRedirect(u){
  const url = safeURL(u);
  if(!url) return u;
  const host = url.hostname.toLowerCase();
  if(REDIRECT_HOSTS.some(h => host === h || host.endsWith('.'+h))){
    const target = firstQueryParam(url);
    if(target){
      const inner = ensureHttp(decodeURIComponent(target));
      const innerUrl = safeURL(inner);
      if(innerUrl) return innerUrl.toString();
    }
  }
  return url.toString();
}

function hostnameOf(u){
  const url = safeURL(u);
  if(url) return url.hostname.toLowerCase();
  const m = String(u).toLowerCase().match(/^(?:https?:\/\/)?([^\/?#]+)/);
  return m ? m[1] : '';
}

function normalizeLinkedIn(u){
  const url = safeURL(u);
  if(!url) return u;
  if(!url.hostname.toLowerCase().includes('linkedin.com')) return u;
  const parts = url.pathname.split('/').filter(Boolean);
  const adminIdx = parts.indexOf('admin');
  if(adminIdx > -1){
    const trimmed = parts.slice(0, adminIdx);
    url.pathname = '/' + trimmed.join('/') + '/';
    url.search = '';
    url.hash = '';
  }
  return url.toString();
}

function platformOfHost(host){
  if(!host) return 'other';
  if(host === 'x.com' || host.includes('twitter.com') || host.includes('mobile.twitter.com')) return 'x';
  if(host.includes('instagram.com')) return 'instagram';
  if(host.includes('facebook.com')) return 'facebook';
  if(host.includes('linkedin.com')) return 'linkedin';
  if(host.includes('tiktok.com')) return 'tiktok';
  if(host.includes('youtube.com') || host === 'youtu.be') return 'youtube';
  if(host.includes('pinterest.')) return 'pinterest';
  if(host === 'wa.me' || host.includes('whatsapp.com')) return 'whatsapp';
  return 'other';
}

function classifyLink(raw){
  const step1 = ensureHttp(raw);
  const step2 = unwrapRedirect(step1);
  const host = hostnameOf(step2);
  let platform = platformOfHost(host);
  let url = step2;
  if(platform === 'linkedin') url = normalizeLinkedIn(step2);
  return { raw, normalized: url, host, platform };
}

function extractUrlsFromText(text){
  if(!text || typeof text !== 'string') return [];
  const re = /https?:\/\/[^\s)>"']+/gi;
  const out = [];
  let m;
  while((m = re.exec(text)) !== null) out.push(m[0]);
  return out;
}

function collectAllLinks(page){
  const bag = new Set();
  for(const l of asArray(page.links)) if(typeof l === 'string') bag.add(l);
  for(const a of asArray(page.articles)) if(typeof a === 'string')
    extractUrlsFromText(a).forEach(u => bag.add(u));
  if(page?.meta?.description)
    extractUrlsFromText(String(page.meta.description)).forEach(u => bag.add(u));
  return [...bag];
}

function guessCompanyName(title, url){
  if(title && typeof title === 'string'){
    const cut = title.split(/[-—|]/)[0].trim();
    if(cut) return cut;
  }
  try{
    const host = new URL(url || '').hostname.replace(/^www\./i,'');
    const root = (host.split('.')[0] || host).replace(/[-_]+/g,' ').trim();
    return root ? root.replace(/\w\S*/g, s => s[0].toUpperCase() + s.slice(1)) : 'Unknown';
  }catch{ return 'Unknown'; }
}

function extractPagesFromItems(items){
  const pages = [];
  for(const it of items){
    const j = it?.json ?? it ?? {};
    if(Array.isArray(j)) { pages.push(...j); continue; }
    if(Array.isArray(j.data)) { pages.push(...j.data); continue; }
    if(Array.isArray(j.results)) { pages.push(...j.results); continue; }
    if(Array.isArray(j.items)) { pages.push(...j.items); continue; }
    pages.push(j);
  }
  return pages;
}

/* ---------------------- generic profile extraction ---------------------- */
function normalizeWhitespace(s){
  return String(s || '')
    .replace(/\r/g,' ')
    .replace(/\t/g,' ')
    .replace(/[ \u00A0]+/g,' ')
    .replace(/\n{3,}/g,'\n\n')
    .trim();
}

function mergeArticleText(page){
  const parts = [];
  if(page?.meta?.description) parts.push(String(page.meta.description));
  for(const a of asArray(page.articles)) if(typeof a === 'string') parts.push(a);
  const joined = parts.join('\n\n');
  return normalizeWhitespace(joined);
}

function truncate(s, n){
  if(!s) return '';
  return s.length <= n ? s : s.slice(0, n-1).trimEnd() + '…';
}

// Generic tokenization & frequency — returns top tokens (excludes stop words, digits)
function topKeyPhrases(text, max=25){
  const stop = new Set([
    'the','and','for','with','your','our','are','you','to','of','in','on','at','a','an','by','is','it',
    'from','as','be','or','that','this','we','they','their','them','us','will','now','get','join','more',
    'free','read','view','all','how','does','works','app','feature','features','class','classes','book',
    'contact','about','login','signup','sign','learn','discover','explore','start','startups',
    'today','now','new','latest','news','blog','case','study','case-study','faq','help','support'
  ]);
  const tokens = (text.toLowerCase().match(/[a-z0-9+.#-]{3,}/g) || [])
    .map(t => t.replace(/^[^a-z0-9]+|[^a-z0-9]+$/g,''))
    .filter(t => t && !stop.has(t) && !/^\d+$/.test(t));
  const freq = new Map();
  for(const t of tokens) freq.set(t, (freq.get(t)||0)+1);
  return [...freq.entries()]
    .sort((a,b)=>b[1]-a[1])
    .slice(0, max)
    .map(([k])=>k);
}

// Pull likely "offerings/services/products" in a neutral way
function detectOfferings(text){
  const lines = text.split(/\n+/).map(s => s.trim()).filter(Boolean);

  // Heuristics:
  // 1) Short heading-like lines (title case / ALL CAPS / bullet-like)
  // 2) Lines following known section cues (e.g., "Our Services", "Products", "Courses")
  // 3) Frequent noun-ish key phrases filtered from key_phrases
  const sectionCue = /(our (products|services|solutions|offerings)|what we (do|offer)|capabilities|courses|programs|packages|plans|pricing)/i;

  const bullets = [];
  for(let i=0;i<lines.length;i++){
    const line = lines[i];
    const isBullet = /^[-•*●▪︎▫︎■□►▶︎] /.test(line);
    const isHeadingLike = /^[A-Z0-9][A-Za-z0-9 .&/(),+-]{3,80}$/.test(line) && !/[.!?]$/.test(line);
    const prevCue = i>0 && sectionCue.test(lines[i-1]);

    if(isBullet || isHeadingLike || prevCue){
      const clean = line.replace(/^[-•*●▪︎▫︎■□►▶︎]\s*/,'').trim();
      if(
        clean.length <= 90 &&
        !/^(read more|view all|contact|about|blog|testimonials?|pricing|download|login|sign ?in|sign ?up)$/i.test(clean)
      ){
        bullets.push(clean);
      }
    }
  }

  // Fold/normalize similar bullets
  const folded = bullets
    .map(s => s.replace(/\s{2,}/g,' ').replace(/\s*[-–|]\s*/g,' - '))
    .filter(Boolean);

  // Backfill with frequent key phrases that look "nouny"
  const kp = topKeyPhrases(text, 30).filter(p => /[a-z]/i.test(p) && !/^(read|view|book|call|click|download)$/i.test(p));
  const nouny = kp.filter(p => !/(today|now|latest|news|blog|about|contact)/i.test(p));

  // Combine and de-dupe
  const out = uniq([...folded, ...nouny]).slice(0, 30);
  return out;
}

// Wide geo dictionary (editable)
const GEO_TERMS = [
  'UAE','Dubai','Abu Dhabi','Sharjah','Saudi Arabia','KSA','Qatar','Kuwait','Bahrain','Oman',
  'Pakistan','India','Bangladesh','Sri Lanka','Nepal',
  'USA','United States','UK','United Kingdom','Canada','Australia','New Zealand',
  'Germany','France','Spain','Italy','Netherlands','Poland','Sweden','Norway','Denmark','Finland','Ireland',
  'South Africa','Nigeria','Kenya','Egypt','Morocco',
  'Singapore','Malaysia','Indonesia','Philippines','Vietnam','Thailand','Japan','South Korea','China','Hong Kong','Taiwan',
  'Brazil','Mexico','Argentina','Chile','Colombia','Peru','UAE'
];

function detectRegions(text){
  const regions = new Set();
  for(const term of GEO_TERMS){
    if(new RegExp(`\\b${term.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}\\b`, 'i').test(text)){
      // normalize a few common variants
      const norm = (term === 'United States') ? 'USA'
                 : (term === 'United Kingdom') ? 'UK'
                 : term;
      regions.add(norm);
    }
  }
  return [...regions];
}

/* ------------------------------ main ------------------------------ */
const pages = extractPagesFromItems(inputs);
const out = [];

for(const page of pages){
  const article_url = page.url || page.pageUrl || page.source || null;
  const company = guessCompanyName(page.title, article_url);
  const website = article_url || null;

  // socials
  const rawLinks = collectAllLinks(page);
  const buckets = {
    instagram:[], facebook:[], linkedin:[], youtube:[],
    tiktok:[], x:[], pinterest:[], whatsapp:[], other:[]
  };
  const classified = rawLinks.map(classifyLink);
  for(const c of classified){
    const list = buckets[c.platform] || buckets.other;
    list.push(c.normalized);
  }
  for(const k of Object.keys(buckets)) buckets[k] = uniq(buckets[k]);
  const all = uniq(Object.values(buckets).flat());

  // profile text (generic)
  const profile_text = mergeArticleText(page);
  const summary_512 = truncate(profile_text, 512);
  const key_phrases = topKeyPhrases(profile_text, 25);
  const offerings_detected = detectOfferings(profile_text);
  const regions_detected = detectRegions(profile_text);

  const socials_present = Object.fromEntries(
    Object.entries(buckets).map(([k,v]) => [k, (v||[]).length>0])
  );

  const profile_for_llm = {
    company,
    website,
    summary: summary_512,
    offerings: offerings_detected,
    regions: regions_detected,
    socials_present
  };

  out.push({
    json: {
      company,
      article_url,
      socials: { by_platform: buckets, all },
      company_profile: {
        name: company,
        website,
        profile_text,
        summary_512,
        key_phrases,
        offerings_detected,
        regions_detected
      },
      profile_for_llm,
      _debug: {
        total_links_seen: rawLinks.length,
        sample_classification: classified.slice(0, 12),
        scraped_at: page.scrapeTime ?? null,
        title: page.title || null,
        meta_desc_len: (page?.meta?.description || '').length
      }
    }
  });
}

return out;

// n8n Code node: Wrap any incoming data into a single "raw_data" packet

function coerceArray(x) {
  // If it's already an array, keep it
  if (Array.isArray(x)) return x;

  // If it's a string, try to JSON.parse; if it's JSON array, return it, else wrap as single
  if (typeof x === 'string') {
    try {
      const parsed = JSON.parse(x);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      // not JSON, just wrap the raw string
      return [x];
    }
  }

  // If it's an object, look for a nested array in common keys
  if (x && typeof x === 'object') {
    for (const k of ['items', 'data', 'payload', 'raw_posts', 'value']) {
      if (Array.isArray(x[k])) return x[k];
    }
    return [x]; // single object
  }

  // null/undefined/other primitives
  return [];
}

// Collect all incoming items
const incoming = $input.all().map(i => i.json);

// Decide raw posts
let rawPosts = [];
if (incoming.length === 1) {
  rawPosts = coerceArray(incoming[0]);
} else {
  // Many items → merge
  rawPosts = incoming.flatMap(coerceArray);
}

// Ensure each entry is an object so n8n doesn't complain
rawPosts = rawPosts
  .filter(v => v !== undefined && v !== null)
  .map(v => (typeof v === 'object' && !Array.isArray(v) ? v : { value: v }));

const packet = {
  packet_name: 'raw_data',
  version: '1.0',
  generated_utc: new Date().toISOString(),
  source_count: rawPosts.length,
  FB_data: {
    raw_posts: rawPosts
  }
};

// Return ONE item with a proper { json: ... } wrapper
return [{ json: packet }];

