/**
 * n8n Code Node: Universal HTML Finder → Clean/Sanitized HTML (JSON + Binary)
 * - No external requires (works in vm2)
 * - FNV-1a 64-bit hex checksum
 */

// ---------- helpers ----------
function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[^\w\s-]/g, '')
    .trim()
    .replace(/[\s_-]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

// FNV-1a 64-bit checksum (hex)
function fnv1a64(str) {
  let h = BigInt('0xcbf29ce484222325'); // offset basis
  const p = BigInt('0x100000001b3');    // prime
  for (let i = 0; i < str.length; i++) {
    h ^= BigInt(str.charCodeAt(i));
    h = (h * p) & BigInt('0xFFFFFFFFFFFFFFFF');
  }
  let hex = h.toString(16);
  return hex.padStart(16, '0');
}

function stripDangerous(html) {
  if (!html) return '';
  let out = String(html);

  // Remove <script>…</script>
  out = out.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

  // Remove on*="..." handlers
  out = out.replace(/\son[a-z]+\s*=\s*(['"]).*?\1/gi, '');

  // Neutralize javascript: in href/src
  out = out.replace(/\s(href|src)\s*=\s*(['"])\s*javascript:[^'"]*\2/gi, ' $1="#"');

  // Sanitize inline styles: drop expression() and url(javascript:...)
  out = out.replace(/\sstyle\s*=\s*(['"])(?:(?!\1).)*\1/gi, (m) => {
    const val = m.replace(/^style\s*=\s*(['"])/i, '').replace(/['"]$/, '');
    const safe = val
      .replace(/expression\s*\([^)]*\)/gi, '')
      .replace(/url\(\s*['"]?\s*javascript:[^)]+?\)/gi, 'url(#)');
    return ` style="${safe}"`;
  });

  // Remove iframes (allowlist later if needed)
  out = out.replace(/<iframe\b[^>]*>([\s\S]*?)<\/iframe>/gi, '');

  return out;
}

function ensureHtmlShell(bodyInner, headTitle = 'Analysis Report') {
  const title = headTitle || 'Analysis Report';
  const head = `
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1">
    <title>${title}</title>
  `.trim();

  return [
    '<!DOCTYPE html>',
    '<html lang="en">',
    '<head>',
    head,
    '</head>',
    '<body>',
    bodyInner || '',
    '</body>',
    '</html>',
  ].join('\n');
}

// ---------- find HTML in input ----------
const inputItem = items[0] || { json: {} };
const itemJson = inputItem.json || {};

let rawHtml = null;
let foundFieldName = 'unknown';

for (const key of Object.keys(itemJson)) {
  const val = itemJson[key];
  if (typeof val === 'string' && val.toLowerCase().includes('<html')) {
    rawHtml = val;
    foundFieldName = key;
    break;
  }
}

if (!rawHtml) {
  for (const key of Object.keys(itemJson)) {
    const val = itemJson[key];
    if (typeof val === 'string' && /<(div|section|article|main|header|footer|p|h1|h2|h3|table|ul|ol)\b/i.test(val)) {
      rawHtml = val;
      foundFieldName = key;
      break;
    }
  }
}

if (!rawHtml) {
  throw new Error(`Could not find HTML in input. Checked fields: ${Object.keys(itemJson).join(', ')}`);
}

// ---------- extract inner + title ----------
const htmlTagRegex = /<html[^>]*>([\s\S]*?)<\/html>/i;
const match = rawHtml.match(htmlTagRegex);
let innerContent = match && match[1] ? match[1].trim() : rawHtml.trim();

let title = 'Analysis Report';
const titleMatch =
  rawHtml.match(/<title[^>]*>([\s\S]*?)<\/title>/i) ||
  innerContent.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
if (titleMatch && titleMatch[1]) {
  title = titleMatch[1].trim().replace(/\s+/g, ' ').slice(0, 120);
}

// Use only body if present to avoid double heads
const bodyMatch = innerContent.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
if (bodyMatch && bodyMatch[1]) {
  innerContent = bodyMatch[1].trim();
}

// ---------- sanitize + build final ----------
const safeBody = stripDangerous(innerContent);
const finalHtml = ensureHtmlShell(safeBody, title);

// ---------- metadata ----------
const dateString = new Date().toISOString().slice(0, 10);
const slug = `${slugify(title)}-${dateString}`;
const fileName = `${slug || 'extracted-html'}-${dateString}.html`;
const checksum = fnv1a64(finalHtml);

// ---------- output ----------
const buffer = Buffer.from(finalHtml, 'utf8');

return [
  {
    json: {
      message: `HTML found in '${foundFieldName}', sanitized and normalized.`,
      title,
      slug,
      checksum,                 // FNV-1a 64-bit hex
      mime_type: 'text/html',
      file_name: fileName,
      clean_html: finalHtml,    // ← push this directly to Supabase / render frontend
    },
    binary: {
      extracted_html: {
        data: buffer.toString('base64'),
        fileName,
        mimeType: 'text/html',
        fileExtension: 'html',
      },
    },
  },
];

// n8n Function node — Universal Assistant JSON Parser
// Handles various OpenAI/Assistant API response formats
// Supports: GPT responses, Claude responses, direct JSON, code fences, etc.
//
// OUTPUT (default): One item with { subject_company_confirmation, competitors, _meta }
// Set SPLIT_COMPETITORS = true to emit one item per competitor

const SPLIT_COMPETITORS = false;

// ---------- helpers ----------
function firstTruthy(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return undefined;
}

function stripCodeFences(s) {
  if (typeof s !== "string") return s;
  // Handle ```json, ```JSON, or plain ```
  const patterns = [
    /```(?:json|JSON)?\s*([\s\S]*?)```/g,
    /~~~(?:json|JSON)?\s*([\s\S]*?)~~~/g
  ];

  for (const pattern of patterns) {
    const matches = [...s.matchAll(pattern)];
    if (matches.length > 0) {
      // Return the last match (most likely to be the complete one)
      return matches[matches.length - 1][1].trim();
    }
  }
  return s;
}

function extractJsonSlice(s) {
  if (typeof s !== "string") return s;

  // Find the outermost complete JSON object or array
  const braceStart = s.indexOf("{");
  const braceEnd = s.lastIndexOf("}");
  const arrStart = s.indexOf("[");
  const arrEnd = s.lastIndexOf("]");

  let cand = null;

  // Prefer object over array if both present
  if (braceStart !== -1 && braceEnd !== -1 && braceEnd > braceStart) {
    cand = s.slice(braceStart, braceEnd + 1);
  } else if (arrStart !== -1 && arrEnd !== -1 && arrEnd > arrStart) {
    cand = s.slice(arrStart, arrEnd + 1);
  }

  return cand || s;
}

function safeJsonParse(x) {
  // Already an object?
  if (x && typeof x === "object" && !Array.isArray(x)) {
    return x;
  }

  // Already an array?
  if (Array.isArray(x)) return x;

  let s = String(x ?? "").trim();
  if (!s) return null;

  // Remove code fences
  s = stripCodeFences(s).trim();

  // Try direct parse
  try { 
    return JSON.parse(s); 
  } catch (e) {
    // Silent fail, continue trying
  }

  // Try extracting the main JSON structure
  const slice = extractJsonSlice(s);
  if (slice && slice !== s) {
    try { 
      return JSON.parse(slice); 
    } catch (e) {
      // Silent fail
    }
  }

  // Handle double-encoded JSON: "\"{...}\""
  if ((s.startsWith('"') && s.endsWith('"')) || (s.startsWith("'") && s.endsWith("'"))) {
    const unq = s.slice(1, -1)
      .replace(/\\"/g, '"')
      .replace(/\\n/g, '\n')
      .replace(/\\t/g, '\t')
      .replace(/\\r/g, '\r')
      .replace(/\\\\/g, '\\');

    try { 
      return JSON.parse(unq); 
    } catch (e) {
      // Silent fail
    }

    const unqSlice = extractJsonSlice(unq);
    try { 
      return JSON.parse(unqSlice); 
    } catch (e) {
      // Silent fail
    }
  }

  return null;
}

function normUrl(u) {
  if (!u) return null;
  let s = String(u).trim();
  if (!s) return null;
  if (!/^https?:\/\//i.test(s)) {
    s = "https://" + s.replace(/^\/+/, "");
  }
  return s;
}

function toIntOrNull(n) {
  if (n === null || n === undefined || n === "") return null;
  const x = Number(n);
  return Number.isFinite(x) ? Math.trunc(x) : null;
}

function normCompetitor(c = {}) {
  return {
    name: firstTruthy(c.name, c.company, c.title, c.company_name) || "",
    website: normUrl(firstTruthy(c.website, c.url, c.link, c.site)),
    relevance_score: toIntOrNull(firstTruthy(c.relevance_score, c.score, c.rank, c.relevance)),
    description: firstTruthy(c.description, c.desc, c.summary, c.details) || ""
  };
}

function toArray(x) {
  if (Array.isArray(x)) return x;
  if (x == null) return [];
  return [x];
}

// Extract content from various API response formats
function extractContent(item) {
  const j = item.json || item || {};

  // Path 1: OpenAI/GPT format - choices[0].message.content
  if (j.choices && Array.isArray(j.choices) && j.choices.length > 0) {
    const choice = j.choices[0];
    if (choice.message?.content) {
      return choice.message.content;
    }
  }

  // Path 2: Direct message.content
  if (j.message?.content) {
    return j.message.content;
  }

  // Path 3: Content with parts (Claude-style)
  if (j.content?.parts?.[0]?.text) {
    return j.content.parts[0].text;
  }

  // Path 4: Direct content.text
  if (j.content?.text) {
    return j.content.text;
  }

  // Path 5: Direct content field
  if (typeof j.content === "string") {
    return j.content;
  }

  // Path 6: text field
  if (j.text) {
    return j.text;
  }

  // Path 7: raw field
  if (j.raw) {
    return j.raw;
  }

  // Path 8: body field
  if (j.body) {
    return j.body;
  }

  // Path 9: data field (sometimes used in webhooks)
  if (j.data) {
    return j.data;
  }

  // Path 10: The item itself might be a string
  if (typeof item === "string") {
    return item;
  }

  return null;
}

// ---------- main processing ----------
let collected = [];
let parseErrors = [];

// Process all incoming items
for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];

  try {
    const content = extractContent(item);

    if (!content) {
      parseErrors.push({
        item_index: idx,
        error: "No content found",
        preview: JSON.stringify(item).slice(0, 200)
      });
      continue;
    }

    const parsed = safeJsonParse(content);

    if (!parsed) {
      parseErrors.push({
        item_index: idx,
        error: "Failed to parse JSON",
        preview: String(content).slice(0, 200)
      });
      continue;
    }

    // Accept either an object with subject + competitors, OR a bare competitors array
    if (Array.isArray(parsed)) {
      collected.push({ competitors: parsed });
    } else if (parsed && typeof parsed === "object") {
      collected.push(parsed);
    }
  } catch (e) {
    parseErrors.push({
      item_index: idx,
      error: e.message || "Unknown error",
      preview: JSON.stringify(item).slice(0, 200)
    });
  }
}

// If nothing was collected, return empty structure (no errors thrown)
if (collected.length === 0) {
  return [{
    json: {
      subject_company_confirmation: { name: null, website: null },
      competitors: [],
      _meta: {
        parser: "universal_assistant_parser_v2.0",
        input_items: items.length,
        parsed_sources: 0,
        competitors_count: 0,
        parse_errors: parseErrors,
        generated_at: new Date().toISOString()
      }
    }
  }];
}

// Pick the most complete object
function pickMostComplete(arr) {
  // Prefer an object that has a competitors array with items
  let best = null;
  let maxCompetitors = 0;

  for (const o of arr) {
    if (o && typeof o === "object" && Array.isArray(o.competitors)) {
      if (o.competitors.length > maxCompetitors) {
        best = o;
        maxCompetitors = o.competitors.length;
      }
    }
  }

  // If none found, take the first valid object
  if (!best) {
    best = arr.find(o => o && typeof o === "object");
  }

  return best || { competitors: [] };
}

const merged = pickMostComplete(collected);

// Normalize subject company
const subject = (() => {
  const s = merged.subject_company_confirmation || 
            merged.subject_company || 
            merged.subject || 
            {};

  return {
    name: firstTruthy(s.name, s.company, s.company_name, s.title) || null,
    website: normUrl(firstTruthy(s.website, s.official_website, s.url, s.site)) || null,
    description: firstTruthy(s.description, s.desc, s.summary) || null
  };
})();

// Normalize competitors
const competitorsRaw = toArray(merged.competitors || merged.results || merged.items).filter(Boolean);
const competitors = competitorsRaw.map(normCompetitor).filter(c => c.name || c.website);

// Build final payload
const result = {
  subject_company_confirmation: subject,
  competitors,
  _meta: {
    parser: "universal_assistant_parser_v2.0",
    input_items: items.length,
    parsed_sources: collected.length,
    competitors_count: competitors.length,
    parse_errors: parseErrors.length > 0 ? parseErrors : undefined,
    generated_at: new Date().toISOString()
  }
};

// Emit results
if (SPLIT_COMPETITORS && competitors.length > 0) {
  return competitors.map((c, idx) => ({
    json: {
      subject_company_confirmation: subject,
      competitor: c,
      competitor_index: idx,
      _meta: {
        ...result._meta,
        split_mode: true
      }
    }
  }));
} else {
  return [{ json: result }];
}

// n8n Code node (JavaScript)
// Robustly normalize `body.website` into a valid http(s) URL when possible.
// Everything else in the item is preserved as-is.
function normalizeCompanyUrl(input) {
  if (input == null) return input;
  let raw = String(input)
    .trim()
    // remove surrounding quotes if pasted with them
    .replace(/^["']+|["']+$/g, "")
    // strip zero-width and BOM characters
    .replace(/[\u200B-\u200D\uFEFF]/g, "");
  if (!raw) return raw;
  // Fix common scheme typos: http//, https//, http:\, https:\, https:example.com
  raw = raw
    .replace(/^https?\s*\/\//i, (m) => m.replace(/\s*/g, ""))        // http // -> http//
    .replace(/^https?(?=\/\/)/i, (m) => m.toLowerCase() + ":")        // http// -> http://
    .replace(/^https?:\\{1,2}/i, (m) => m.toLowerCase().replace(/\\+/g, "://")) // http:\\ -> http://
    .replace(/^https?:\s*(?=[^/])/i, (m) => m.toLowerCase() + "//");  // https:example.com -> https://example.com
  // If it starts with //example.com, default to https
  if (/^\/\//.test(raw)) raw = "https:" + raw;
  // If no scheme at all, prepend https://
  if (!/^[a-z][a-z0-9+.-]*:\/\//i.test(raw)) {
    // Handle bare "example.com" or "www.example.com/path"
    raw = "https://" + raw;
  }
  // Collapse extra slashes after scheme (https:////example.com -> https://example.com)
  raw = raw.replace(/^(https?:)\/\/+/, "$1//");
  // Attempt URL parsing; if it fails due to spaces, try encoding them.
  const tryParse = (s) => {
    try {
      return new URL(s);
    } catch {
      return null;
    }
  };
  let url = tryParse(raw) || tryParse(raw.replace(/\s+/g, "%20"));
  if (!url) {
    // As a last mild cleanup: remove spaces entirely (domain shouldn't have spaces)
    url = tryParse(raw.replace(/\s+/g, ""));
  }
  if (!url) return raw; // give back best-effort string if still unparsable
  // Only normalize http/https; leave other schemes (mailto:, ftp:, etc.) untouched
  if (!/^https?:$/i.test(url.protocol)) {
    return url.toString();
  }
  // Normalize host to lowercase
  url.hostname = url.hostname.toLowerCase();
  // Remove default ports
  if ((url.protocol === "http:" && url.port === "80") ||
      (url.protocol === "https:" && url.port === "443")) {
    url.port = "";
  }
  // Collapse duplicate slashes in pathname (but keep leading single slash)
  url.pathname = url.pathname.replace(/\/{2,}/g, "/");
  // Preserve a trailing slash if there's no filename (URL API will add it anyway for empty path)
  // Nothing extra needed; URL will ensure trailing slash for empty path.
  return url.toString();
}

return items.map((item) => {
  // deep clone to avoid mutating prior nodes' data
  const out = JSON.parse(JSON.stringify(item.json ?? item));
  if (out && out.body && typeof out.body.website !== "undefined") {
    out.body.website = normalizeCompanyUrl(out.body.website);
  }
  return { json: out };
});

