/**
 * n8n Code node — Parse 3-slide carousel JSON (Gemini/OpenAI style)
 *
 * Input example (from LLM):
 * [
 *   {
 *     "content": {
 *       "parts": [{ "text": "{ \"Slide_1\": {\"Title\":\"...\",\"Description\":\"...\"}, ... }" }],
 *       "role": "model"
 *     }
 *   }
 * ]
 *
 * Output (items):
 * [
 *   { json: { slide: "Slide_1", index: 1, Title: "...", Description: "..." } },
 *   { json: { slide: "Slide_2", index: 2, Title: "...", Description: "..." } },
 *   { json: { slide: "Slide_3", index: 3, Title: "...", Description: "..." } }
 * ]
 */

function collectCandidateTexts(obj) {
  const texts = [];
  if (typeof obj?.text === "string") texts.push(obj.text);
  if (typeof obj?.output === "string") texts.push(obj.output);

  const candidates = obj?.candidates;
  if (Array.isArray(candidates)) {
    for (const c of candidates) {
      const parts = c?.content?.parts;
      if (Array.isArray(parts)) {
        for (const p of parts) if (typeof p?.text === "string") texts.push(p.text);
      }
      if (typeof c?.text === "string") texts.push(c.text);
    }
  }

  const content = obj?.content;
  if (Array.isArray(content)) {
    for (const part of content) if (typeof part?.text === "string") texts.push(part.text);
  } else if (content?.parts && Array.isArray(content.parts)) {
    for (const part of content.parts) if (typeof part?.text === "string") texts.push(part.text);
  }

  return texts.filter(t => typeof t === "string" && t.trim().length > 0);
}

function stripCodeFences(s) {
  const fenceRe = /```(?:json)?\s*([\s\S]*?)```/gi;
  let m, best = "";
  while ((m = fenceRe.exec(s)) !== null) {
    const candidate = m[1].trim();
    if (candidate.length > best.length) best = candidate;
  }
  if (best) return best;

  const first = s.indexOf("{");
  const last  = s.lastIndexOf("}");
  if (first !== -1 && last !== -1 && last > first) return s.slice(first, last + 1).trim();
  return s.trim();
}

function cleanForJson(s) {
  let out = s.replace(/\r\n/g, "\n").replace(/[\u200B-\u200D\uFEFF]/g, "").trim();

  // Handle double-encoded strings (e.g., "{\"Slide_1\":...}")
  if ((/^["']/.test(out) && /\\["']?\{/.test(out)) || (out.includes('\\"Slide_1\\"') || out.includes('\\"Slide_2\\"'))) {
    try {
      const unescaped = JSON.parse(out);
      if (typeof unescaped === "string") out = unescaped.trim();
    } catch (_) {}
  }
  return out;
}

function tryParseJson(s) {
  try {
    return JSON.parse(s);
  } catch (_) {}
  // remove trailing commas
  const t = s.replace(/,\s*([}\]])/g, "$1");
  if (t !== s) {
    try { return JSON.parse(t); } catch (_) {}
  }
  throw new Error("Payload is not valid JSON after cleaning");
}

function toStringValue(v) {
  if (v === undefined || v === null) return "";
  if (typeof v === "string") return v;
  if (typeof v === "number" || typeof v === "boolean") return String(v);
  return JSON.stringify(v);
}

function pick(obj, key) {
  const v = obj?.[key];
  return toStringValue(v);
}

const outputs = [];

for (const item of items) {
  const src = item.json || {};
  const texts = collectCandidateTexts(src);
  if (texts.length === 0) {
    throw new Error("No candidate text found to parse.");
  }

  const best = texts.reduce((a, b) => (b.length > a.length ? b : a), "");
  const cleaned = cleanForJson(stripCodeFences(best));
  const parsed = tryParseJson(cleaned);

  if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
    throw new Error("Parsed content is not an object.");
  }

  const slideKeys = ["Slide_1", "Slide_2", "Slide_3"];
  let found = false;

  slideKeys.forEach((sk, i) => {
    const sObj = parsed[sk] && typeof parsed[sk] === "object" ? parsed[sk] : {};
    const Title = pick(sObj, "Title");
    const Description = pick(sObj, "Description");
    // Only push if either field exists; else still push empty to keep 3 slides consistent
    outputs.push({
      json: {
        slide: sk,
        index: i + 1,
        Title,
        Description,
      },
    });
    found = true;
  });

  if (!found) {
    throw new Error("No Slide_1/Slide_2/Slide_3 keys found in JSON.");
  }
}

return outputs;

