// n8n Code node (JavaScript)
// Robustly normalize `body.company` into a valid http(s) URL when possible.
// Everything else in the item is preserved as-is.

function normalizeCompanyUrl(input) {
  if (input == null) return input;

  let raw = String(input)
    .trim()
    // remove surrounding quotes if pasted with them
    .replace(/^["']+|["']+$/g, "")
    // strip zero-width and BOM characters
    .replace(/[\u200B-\u200D\uFEFF]/g, "");

  if (!raw) return raw;

  // Fix common scheme typos: http//, https//, http:\, https:\, https:example.com
  raw = raw
    .replace(/^https?\s*\/\//i, (m) => m.replace(/\s*/g, ""))        // http // -> http//
    .replace(/^https?(?=\/\/)/i, (m) => m.toLowerCase() + ":")        // http// -> http://
    .replace(/^https?:\\{1,2}/i, (m) => m.toLowerCase().replace(/\\+/g, "://")) // http:\\ -> http://
    .replace(/^https?:\s*(?=[^/])/i, (m) => m.toLowerCase() + "//");  // https:example.com -> https://example.com

  // If it starts with //example.com, default to https
  if (/^\/\//.test(raw)) raw = "https:" + raw;

  // If no scheme at all, prepend https://
  if (!/^[a-z][a-z0-9+.-]*:\/\//i.test(raw)) {
    // Handle bare "example.com" or "www.example.com/path"
    raw = "https://" + raw;
  }

  // Collapse extra slashes after scheme (https:////example.com -> https://example.com)
  raw = raw.replace(/^(https?:)\/\/+/, "$1//");

  // Attempt URL parsing; if it fails due to spaces, try encoding them.
  const tryParse = (s) => {
    try {
      return new URL(s);
    } catch {
      return null;
    }
  };

  let url = tryParse(raw) || tryParse(raw.replace(/\s+/g, "%20"));
  if (!url) {
    // As a last mild cleanup: remove spaces entirely (domain shouldn't have spaces)
    url = tryParse(raw.replace(/\s+/g, ""));
  }
  if (!url) return raw; // give back best-effort string if still unparsable

  // Only normalize http/https; leave other schemes (mailto:, ftp:, etc.) untouched
  if (!/^https?:$/i.test(url.protocol)) {
    return url.toString();
  }

  // Normalize host to lowercase
  url.hostname = url.hostname.toLowerCase();

  // Remove default ports
  if ((url.protocol === "http:" && url.port === "80") ||
      (url.protocol === "https:" && url.port === "443")) {
    url.port = "";
  }

  // Collapse duplicate slashes in pathname (but keep leading single slash)
  url.pathname = url.pathname.replace(/\/{2,}/g, "/");

  // Preserve a trailing slash if there’s no filename (URL API will add it anyway for empty path)
  // Nothing extra needed; URL will ensure trailing slash for empty path.

  return url.toString();
}

return items.map((item) => {
  // deep clone to avoid mutating prior nodes' data
  const out = JSON.parse(JSON.stringify(item.json ?? item));

  if (out && out.body && typeof out.body.website !== "undefined") {
    out.body.website = normalizeCompanyUrl(out.body.website);
  }

  return { json: out };
});

// For n8n Code Node - Run Once for All Items mode
const allImages = [];

// Iterate through all input items
for (const item of $input.all()) {
  const data = item.json;

  // Check if imageUrns exists and is an array
  if (data.imageUrns && Array.isArray(data.imageUrns)) {
    // Add all URNs from this item
    data.imageUrns.forEach(urn => {
      allImages.push({ id: urn });
    });
  }
}

// Return in n8n format - array with single item containing the images object
return [{ json: { images: allImages } }];

/* 
Example Input (each item):
{
  "imageUrns": [
    "urn:li:image:D4D10AQEZ6KYTPijiBw",
    "urn:li:image:D4D10AQHbsB35GG7HbA"
  ]
}

Output:
{
  "images": [
    { "id": "urn:li:image:D4D10AQEZ6KYTPijiBw" },
    { "id": "urn:li:image:D4D10AQHbsB35GG7HbA" }
  ]
}
*/

// Code node to build LinkedIn post body with debugging

const allImages = [];

// Get all input items
const inputItems = $input.all();

// Debug: Log what we're receiving
console.log('Number of input items:', inputItems.length);

// Collect all image URNs from input items
for (const item of inputItems) {
  const data = item.json;

  console.log('Processing item:', JSON.stringify(data));

  // Check different possible data structures
  if (data.imageUrns && Array.isArray(data.imageUrns)) {
    console.log('Found imageUrns array with', data.imageUrns.length, 'items');
    data.imageUrns.forEach(urn => {
      allImages.push({ id: urn });
    });
  } else if (data.images && Array.isArray(data.images)) {
    console.log('Found images array with', data.images.length, 'items');
    data.images.forEach(img => {
      if (img.id) {
        allImages.push({ id: img.id });
      } else if (typeof img === 'string') {
        allImages.push({ id: img });
      }
    });
  } else {
    console.log('No imageUrns or images array found in item');
  }
}

console.log('Total images collected:', allImages.length);

// Get data from If2 node
const if2Data = $('If2').item.json;

// Build the complete LinkedIn post body
const requestBody = {
  author: `urn:li:organization:${if2Data.linkedin_organization_id}`,
  commentary: if2Data.description,
  visibility: "PUBLIC",
  distribution: {
    feedDistribution: "MAIN_FEED",
    targetEntities: [],
    thirdPartyDistributionChannels: []
  },
  lifecycleState: "PUBLISHED",
  isReshareDisabledByAuthor: false,
  content: {
    multiImage: {
      images: allImages
    }
  }
};

// Validate we have enough images
if (allImages.length < 2) {
  throw new Error(`LinkedIn requires 2-20 images. Only found ${allImages.length} images. Check your input data structure.`);
}

console.log('Final request body:', JSON.stringify(requestBody, null, 2));

// Return the body ready for HTTP Request node
return [{ json: { requestBody } }];

const videoUrn = $input.first().json.body.value.video
const orgId = $('If2').first().json.meta.selected_organization.id
const caption = $('If2').first().json.description

const postBody = {
  author: `urn:li:organization:${orgId}`,
  commentary: caption,
  visibility: "PUBLIC",
  distribution: {
    feedDistribution: "MAIN_FEED",
    targetEntities: [],
    thirdPartyDistributionChannels: []
  },
  lifecycleState: "PUBLISHED",
  isReshareDisabledByAuthor: false,
  content: {
    media: {
      id: videoUrn
    } 
  }
};

return [{ json: { requestBody: postBody } }];

const fileSizeStr = $('Get video').item.binary.data.fileSize;
const fileSizeMB = parseFloat(fileSizeStr); // Extract 2.73
const fileSizeBytes = Math.round(fileSizeMB * 1024 * 1024); // Convert to bytes

const orgId = $('If2').item.json.linkedin_organization_id;

const initBody = {
  initializeUploadRequest: {
    owner: `urn:li:organization:${orgId}`,
    fileSizeBytes: fileSizeBytes,
    uploadCaptions: false,
    uploadThumbnail: false
  }
};

return [{ json: { initBody } }];

// Code node: "Pass Binary Data"
const videoNode = $('Get video').item;

return [{
  json: videoNode.json,
  binary: videoNode.binary
}];

