  // Check different possible data structures
  if (data.imageUrns && Array.isArray(data.imageUrns)) {
    console.log('Found imageUrns array with', data.imageUrns.length, 'items');
    data.imageUrns.forEach(urn => {
      allImages.push({ id: urn });
    });
  } else if (data.images && Array.isArray(data.images)) {
    console.log('Found images array with', data.images.length, 'items');
    data.images.forEach(img => {
      if (img.id) {
        allImages.push({ id: img.id });
      } else if (typeof img === 'string') {
        allImages.push({ id: img });
      }
    });
  } else if (data.imageUrn && typeof data.imageUrn === 'string') {
    // Handle single image URN
    console.log('Found single imageUrn');
    allImages.push({ id: data.imageUrn });
  } else {
    console.log('No imageUrns or images array found in item');
  }
}
console.log('Total images collected:', allImages.length);
// Get data from If2 node
const if2Data = $('If2').item.json;
// Build the complete LinkedIn post body
