// Function to convert Base64 string to a binary Buffer and attach it to the item.
const convertBase64ToBinary = (items) => {
  const outputItems = [];

  for (const item of items) {
    // 1. **CRITICAL STEP: Extract the Base64 String**
    // Access the 'data' field directly using the confirmed JSON path.
    const base64Data = item.json.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Data) {
      // If data is missing or path is wrong, skip the item or throw an error.
      console.warn("Base64 image data is missing or the path is incorrect for an input item.");
      outputItems.push(item); // Pass the original item along for debugging/handling
      continue; 
    }

    try {
        // 2. Decode the Base64 string into a Buffer
        // The 'base64' encoding parameter is essential for decoding.
        const buffer = Buffer.from(base64Data, 'base64');

        // 3. Create the Binary Object Metadata
        const binaryData = {
          data: buffer,
          // Confirmed to be JPEG from the /9j/ header
          mimeType: 'image/jpeg', 
          // Create a unique filename for the output file
