// n8n Function node
// Input: items[].json.output  (string or object containing { calendar: [...] } or variants)
// Output: one item per calendar row with EXACT keys in this order (no extras).

const REQUIRED = [
  'Date',
  'Time',
  'Platform',
  'Pillar',
  'Topic',
  'Posting Idea (Strategy Only)',
  'Hashtags',
];

// Collect all possible payload strings/objects from items
function getPayloads(items) {
  const payloads = [];

  for (const it of items) {
    const j = it.json ?? it;

    // Most common: json.output or json.text
    if (j && j.output != null) {
      payloads.push(j.output);
    } else if (j && j.text != null) {
      payloads.push(j.text);
    } else if (it.output != null) {
      payloads.push(it.output);
    } else if (it.text != null) {
      payloads.push(it.text);
    }
  }

  return payloads;
}

// Safely parse JSON from string (and try to trim wrappers)
function parseMaybeJson(strOrObj) {
  // If it’s already an object, just return it
  if (strOrObj && typeof strOrObj === 'object') return strOrObj;

  if (typeof strOrObj !== 'string') return null;
  const str = strOrObj.trim();
  if (!str) return null;

  // Try direct parse
  try {
    return JSON.parse(str);
  } catch (e) {}

  // Try to slice between first { and last }
  const first = str.indexOf('{');
  const last = str.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    const sliced = str.slice(first, last + 1);
    try {
      return JSON.parse(sliced);
    } catch (e) {}
  }

  return null;
}

// Try to extract the calendar array from various common shapes
function extractCalendar(parsed) {
  if (!parsed || typeof parsed !== 'object') return null;

  // 1) If the whole thing is an array of rows
  if (Array.isArray(parsed)) return parsed;

  // 2) Ideal case: { calendar: [...] }
  if (Array.isArray(parsed.calendar)) return parsed.calendar;

  // 3) Common wrappers: { data: { calendar: [...] } }, { output: { calendar: [...] } }, etc.
  const wrappers = ['data', 'output', 'result', 'response'];
  for (const key of wrappers) {
    if (parsed[key] && Array.isArray(parsed[key].calendar)) {
      return parsed[key].calendar;
    }
  }

  // 4) Your sample: { type:"object", properties:{ calendar:[...] } }
  if (parsed.properties) {
    // Direct array: properties.calendar = [...]
    if (Array.isArray(parsed.properties.calendar)) {
      return parsed.properties.calendar;
    }

    // JSON-schema-like: properties.calendar = { type:"array", items:[...] }
    if (
      parsed.properties.calendar &&
      Array.isArray(parsed.properties.calendar.items)
    ) {
      return parsed.properties.calendar.items;
    }
  }

  // 5) JSON-schema-like at top level: { calendar:{ type:"array", items:[...] } }
  if (
    parsed.calendar &&
    !Array.isArray(parsed.calendar) &&
    Array.isArray(parsed.calendar.items)
  ) {
    return parsed.calendar.items;
  }

  // 6) Last resort: scan for any property that is an array of row-ish objects (has Date or Topic)
  for (const key of Object.keys(parsed)) {
    const val = parsed[key];
    if (Array.isArray(val) && val.length && typeof val[0] === 'object') {
      const firstRow = val[0];
      if ('Date' in firstRow || 'Topic' in firstRow || 'Platform' in firstRow) {
        return val;
      }
    }
  }

  return null;
}

// ---- Main logic ----

const payloads = getPayloads(items);
const out = [];

for (const payload of payloads) {
  const parsed = parseMaybeJson(payload);
  const calendar = extractCalendar(parsed);

  if (!calendar || !Array.isArray(calendar)) {
    continue; // nothing usable in this payload
  }

  for (const row of calendar) {
    if (!row || typeof row !== 'object') continue;

    // Extract fields with exact keys
    const date     = (row['Date'] ?? '').toString().trim();
    const time     = (row['Time'] ?? '').toString().trim();
    const platform = (row['Platform'] ?? '').toString().trim();
    const pillar   = (row['Pillar'] ?? '').toString().trim();
    const topic    = (row['Topic'] ?? '').toString().trim();
    const idea     = (row['Posting Idea (Strategy Only)'] ?? '').toString().trim();

    const hashtags = ((row['Hashtags'] ?? '') + '')
      .replace(/\s+/g, ' ')
      .trim();

    // Skip rows that are clearly incomplete (no date and no topic)
    if (!date && !topic) continue;

    out.push({
      json: {
        [REQUIRED[0]]: date,
        [REQUIRED[1]]: time,
        [REQUIRED[2]]: platform,
        [REQUIRED[3]]: pillar,
        [REQUIRED[4]]: topic,
        [REQUIRED[5]]: idea,
        [REQUIRED[6]]: hashtags,
      },
    });
  }
}

return out;

