// n8n Code node (JavaScript)

const items = $input.all();

return items.map(item => {
  let parsed = {};

  try {
    // item.json.output contains the JSON string with prompts or other keys
    parsed = JSON.parse(item.json.output);
  } catch (error) {
    parsed = {
      parseError: error.message,
      rawOutput: item.json.output,
    };
  }

  // --- Extract prompts into one encapsulated object ---
  const prompts = {};
  if (parsed && typeof parsed === "object") {
    Object.keys(parsed).forEach(key => {
      if (key.toLowerCase().includes("prompt")) {
        prompts[key] = parsed[key];
      }
    });
  }

  return {
    json: {
      // keep original fields
      ...item.json,

      // spread parsed fields
      ...parsed,

      // add encapsulated prompt variable
      prompts: prompts
    },
  };
});

