// ALWAYS prepend the greeting with customer name placeholder
const firstMessage = `Hello {{customer.name}}, are you there? Can you hear me? ${baseWelcomeMessage}`;

// VOICE - Now dynamic from input (11Labs)
const voiceId = data.body?.voice || data.voiceId || "Kylie"; // Fallback to "Kylie" if not found
if (!voiceId) throw new Error("❌ Voice ID missing!");

// LANGUAGE
