// n8n Function node
// Accepts: single site object, array of sites, or {competitors:[]}/{data:[]}
// Emits: one item per site with { name, website, domain, socials{...} }

function parseHost(u) {
  if (typeof u !== 'string') return '';
  // strip protocol, credentials, and port, then take host
  const noProto = u.replace(/^\s*/,'').replace(/^https?:\/\//i, '');
  const noCreds = noProto.replace(/^[^/@]+@/, '');
  const host = noCreds.split('/')[0].split('?')[0].split('#')[0];
  return host.replace(/^www\./i, '').toLowerCase();
}

function domainFromUrl(u) {
  const host = parseHost(u);
  // collapse subdomains like m.linkedin.com -> linkedin.com
  const parts = host.split('.').filter(Boolean);
  if (parts.length >= 2) return parts.slice(-2).join('.');
  return host;
}

function pickName(title, website) {
  const host = parseHost(website);
  if (title && typeof title === 'string') {
    let name = title.split(/[|–—-]/)[0].trim();
    name = name.replace(/\b(home|homepage)\b/i, '').trim();
    if (name) return name;
  }
  const base = (host || '').split('.')[0];
  return base ? base.charAt(0).toUpperCase() + base.slice(1) : '';
}

function extractUrlsFromText(text) {
  const out = [];
  const re = /\bhttps?:\/\/[^\s"'<>)]+/gi;
  let m; while ((m = re.exec(text)) !== null) out.push(m[0]);
  return out;
}

function collectAllUrls(site) {
  const urls = new Set();
  if (Array.isArray(site.links)) site.links.forEach(u => { if (typeof u === 'string') urls.add(u); });
  if (Array.isArray(site.articles)) site.articles.forEach(t => {
    if (typeof t === 'string') extractUrlsFromText(t).forEach(u => urls.add(u));
  });
  return Array.from(urls);
}

function normalizeIncoming(items) {
  const sites = [];
  for (const it of (items || [])) {
    let payload = it?.json;
    if (typeof payload === 'string') { try { payload = JSON.parse(payload); } catch {} }
    for (const k of ['body','data']) {
      if (typeof payload?.[k] === 'string') { try { payload[k] = JSON.parse(payload[k]); } catch {} }
    }

    if (Array.isArray(payload)) { payload.forEach(s => s && typeof s === 'object' && sites.push(s)); continue; }
    if (Array.isArray(payload?.competitors)) { payload.competitors.forEach(s => s && sites.push(s)); continue; }
    if (Array.isArray(payload?.data)) { payload.data.forEach(s => s && sites.push(s)); continue; }
    if (Array.isArray(payload?.body)) { payload.body.forEach(s => s && sites.push(s)); continue; }

    if (payload && typeof payload === 'object') {
      const looksLikeSite = ['url','title','links','articles','images','videos','meta']
        .some(k => Object.prototype.hasOwnProperty.call(payload, k));
      if (looksLikeSite) { sites.push(payload); continue; }
    }
  }
  return sites;
}

// ---- Social detectors (host-based, tolerant paths) ----
function firstByHost(urls, host, pathRegex) {
  for (const u of urls) {
    const h = domainFromUrl(u);
    if (h === host) {
      if (!pathRegex) return u;
      const path = (typeof u === 'string' ? u.split(domainFromUrl(u))[1] : '') || '';
      if (pathRegex.test(u)) return u;
    }
  }
  return undefined;
}

const sites = normalizeIncoming(items);

if (!sites.length) {
  const first = items?.[0]?.json ?? null;
  return [{ json: {
    error: 'No site objects found',
    hint: 'Send a site object, an array of sites, or wrap in {competitors:[...] } / {data:[...]}',
    keys: first && typeof first === 'object' ? Object.keys(first) : typeof first
  }}];
}

const out = [];

for (const site of sites) {
  const website = site.url || site.website || site.homepage || '';
  const domain = domainFromUrl(website);
  const urls = collectAllUrls(site);

  const socials = {};
  // LinkedIn (accept company/showcase/school or anything under linkedin.com)
  socials.linkedin  = firstByHost(urls, 'linkedin.com', /(company|showcase|school|in|@)/i) || firstByHost(urls, 'linkedin.com');
  // X / Twitter
  socials.x         = firstByHost(urls, 'x.com') || firstByHost(urls, 'twitter.com');
  // Instagram
  socials.instagram = firstByHost(urls, 'instagram.com');
  // Facebook
  socials.facebook  = firstByHost(urls, 'facebook.com');
  // TikTok
  socials.tiktok    = firstByHost(urls, 'tiktok.com');
  // YouTube (support channel, user, @handle)
  socials.youtube   = firstByHost(urls, 'youtube.com', /\/(@|channel|user)\b/i) || firstByHost(urls, 'youtu.be');

  // prune empties
  Object.keys(socials).forEach(k => !socials[k] && delete socials[k]);

  out.push({
    json: {
      name: pickName(site.title, website),
      website,
      domain,
      socials
    }
  });
}

return [
  {
    json: {
      top5competitors: out.map(i => i.json)
    }
  }
];

