const inputs = $input.all();

/* ------------------------- helpers (generic) ------------------------- */
const REDIRECT_HOSTS = [
  'l.facebook.com','lm.facebook.com','m.facebook.com',
  'lnkd.in','linkedin.com','t.co','bit.ly','tinyurl.com',
  'linktr.ee','lnk.bio','rb.gy','goo.gl','ow.ly'
];

function asArray(x){ return Array.isArray(x) ? x : (x == null ? [] : [x]); }
function uniq(a){ return [...new Set(a.filter(Boolean))]; }

function ensureHttp(u){
  if(!u) return '';
  let s = String(u).trim();
  s = s.replace(/^[<('"`]+|[>)"'`,.]+$/g,'');  // drop stray punct
  if(s.startsWith('//')) s = 'https:' + s;
  if(!/^https?:\/\//i.test(s)) s = 'https://' + s;
  return s;
}

function safeURL(u){ try{ return new URL(u); } catch { return null; } }

function firstQueryParam(url, keys=['u','url','to','dest','destination']){
  for(const k of keys){ const v = url.searchParams.get(k); if(v) return v; }
  return null;
}

function unwrapRedirect(u){
  const url = safeURL(u);
  if(!url) return u;
  const host = url.hostname.toLowerCase();
  if(REDIRECT_HOSTS.some(h => host === h || host.endsWith('.'+h))){
    const target = firstQueryParam(url);
    if(target){
      const inner = ensureHttp(decodeURIComponent(target));
      const innerUrl = safeURL(inner);
      if(innerUrl) return innerUrl.toString();
    }
  }
  return url.toString();
}

function hostnameOf(u){
  const url = safeURL(u);
  if(url) return url.hostname.toLowerCase();
  const m = String(u).toLowerCase().match(/^(?:https?:\/\/)?([^\/?#]+)/);
  return m ? m[1] : '';
}

function normalizeLinkedIn(u){
  const url = safeURL(u);
  if(!url) return u;
  if(!url.hostname.toLowerCase().includes('linkedin.com')) return u;
  const parts = url.pathname.split('/').filter(Boolean);
  const adminIdx = parts.indexOf('admin');
  if(adminIdx > -1){
    const trimmed = parts.slice(0, adminIdx);
    url.pathname = '/' + trimmed.join('/') + '/';
    url.search = '';
    url.hash = '';
  }
  return url.toString();
}

function platformOfHost(host){
  if(!host) return 'other';
  if(host === 'x.com' || host.includes('twitter.com') || host.includes('mobile.twitter.com')) return 'x';
  if(host.includes('instagram.com')) return 'instagram';
  if(host.includes('facebook.com')) return 'facebook';
  if(host.includes('linkedin.com')) return 'linkedin';
  if(host.includes('tiktok.com')) return 'tiktok';
  if(host.includes('youtube.com') || host === 'youtu.be') return 'youtube';
  if(host.includes('pinterest.')) return 'pinterest';
  if(host === 'wa.me' || host.includes('whatsapp.com')) return 'whatsapp';
  return 'other';
}

function classifyLink(raw){
  const step1 = ensureHttp(raw);
  const step2 = unwrapRedirect(step1);
  const host = hostnameOf(step2);
  let platform = platformOfHost(host);
  let url = step2;
  if(platform === 'linkedin') url = normalizeLinkedIn(step2);
  return { raw, normalized: url, host, platform };
}

function extractUrlsFromText(text){
  if(!text || typeof text !== 'string') return [];
  const re = /https?:\/\/[^\s)>"']+/gi;
  const out = [];
  let m;
  while((m = re.exec(text)) !== null) out.push(m[0]);
  return out;
}

function collectAllLinks(page){
  const bag = new Set();
  for(const l of asArray(page.links)) if(typeof l === 'string') bag.add(l);
  for(const a of asArray(page.articles)) if(typeof a === 'string')
    extractUrlsFromText(a).forEach(u => bag.add(u));
  if(page?.meta?.description)
    extractUrlsFromText(String(page.meta.description)).forEach(u => bag.add(u));
  return [...bag];
}

function guessCompanyName(title, url){
  if(title && typeof title === 'string'){
    const cut = title.split(/[-—|]/)[0].trim();
    if(cut) return cut;
  }
  try{
    const host = new URL(url || '').hostname.replace(/^www\./i,'');
    const root = (host.split('.')[0] || host).replace(/[-_]+/g,' ').trim();
    return root ? root.replace(/\w\S*/g, s => s[0].toUpperCase() + s.slice(1)) : 'Unknown';
  }catch{ return 'Unknown'; }
}

function extractPagesFromItems(items){
  const pages = [];
  for(const it of items){
    const j = it?.json ?? it ?? {};
    if(Array.isArray(j)) { pages.push(...j); continue; }
    if(Array.isArray(j.data)) { pages.push(...j.data); continue; }
    if(Array.isArray(j.results)) { pages.push(...j.results); continue; }
    if(Array.isArray(j.items)) { pages.push(...j.items); continue; }
    pages.push(j);
  }
  return pages;
}

