function normalizeWhitespace(s){
  return String(s || '')
    .replace(/\r/g,' ')
    .replace(/\t/g,' ')
    .replace(/[ \u00A0]+/g,' ')
    .replace(/\n{3,}/g,'\n\n')
    .trim();
}

function mergeArticleText(page){
  const parts = [];
  if(page?.meta?.description) parts.push(String(page.meta.description));
  for(const a of asArray(page.articles)) if(typeof a === 'string') parts.push(a);
  const joined = parts.join('\n\n');
  return normalizeWhitespace(joined);
}

function truncate(s, n){
  if(!s) return '';
  return s.length <= n ? s : s.slice(0, n-1).trimEnd() + '…';
}

// Generic tokenization & frequency — returns top tokens (excludes stop words, digits)
function topKeyPhrases(text, max=25){
  const stop = new Set([
    'the','and','for','with','your','our','are','you','to','of','in','on','at','a','an','by','is','it',
    'from','as','be','or','that','this','we','they','their','them','us','will','now','get','join','more',
    'free','read','view','all','how','does','works','app','feature','features','class','classes','book',
    'contact','about','login','signup','sign','learn','discover','explore','start','startups',
    'today','now','new','latest','news','blog','case','study','case-study','faq','help','support'
  ]);
  const tokens = (text.toLowerCase().match(/[a-z0-9+.#-]{3,}/g) || [])
    .map(t => t.replace(/^[^a-z0-9]+|[^a-z0-9]+$/g,''))
    .filter(t => t && !stop.has(t) && !/^\d+$/.test(t));
  const freq = new Map();
  for(const t of tokens) freq.set(t, (freq.get(t)||0)+1);
  return [...freq.entries()]
    .sort((a,b)=>b[1]-a[1])
    .slice(0, max)
    .map(([k])=>k);
}

// Pull likely "offerings/services/products" in a neutral way
function detectOfferings(text){
  const lines = text.split(/\n+/).map(s => s.trim()).filter(Boolean);

  // Heuristics:
  // 1) Short heading-like lines (title case / ALL CAPS / bullet-like)
  // 2) Lines following known section cues (e.g., "Our Services", "Products", "Courses")
  // 3) Frequent noun-ish key phrases filtered from key_phrases
  const sectionCue = /(our (products|services|solutions|offerings)|what we (do|offer)|capabilities|courses|programs|packages|plans|pricing)/i;

  const bullets = [];
  for(let i=0;i<lines.length;i++){
    const line = lines[i];
    const isBullet = /^[-•*●▪︎▫︎■□►▶︎] /.test(line);
    const isHeadingLike = /^[A-Z0-9][A-Za-z0-9 .&/(),+-]{3,80}$/.test(line) && !/[.!?]$/.test(line);
    const prevCue = i>0 && sectionCue.test(lines[i-1]);

    if(isBullet || isHeadingLike || prevCue){
      const clean = line.replace(/^[-•*●▪︎▫︎■□►▶︎]\s*/,'').trim();
      if(
        clean.length <= 90 &&
        !/^(read more|view all|contact|about|blog|testimonials?|pricing|download|login|sign ?in|sign ?up)$/i.test(clean)
      ){
        bullets.push(clean);
      }
    }
  }

  // Fold/normalize similar bullets
  const folded = bullets
    .map(s => s.replace(/\s{2,}/g,' ').replace(/\s*[-–|]\s*/g,' - '))
    .filter(Boolean);

  // Backfill with frequent key phrases that look "nouny"
  const kp = topKeyPhrases(text, 30).filter(p => /[a-z]/i.test(p) && !/^(read|view|book|call|click|download)$/i.test(p));
  const nouny = kp.filter(p => !/(today|now|latest|news|blog|about|contact)/i.test(p));

  // Combine and de-dupe
  const out = uniq([...folded, ...nouny]).slice(0, 30);
  return out;
}

