 * n8n Code Node: Universal HTML Finder → Clean/Sanitized HTML (JSON + Binary)
 * - No external requires (works in vm2)
 * - FNV-1a 64-bit hex checksum
 */

// ---------- helpers ----------
function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[^\w\s-]/g, '')
    .trim()
    .replace(/[\s_-]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

// FNV-1a 64-bit checksum (hex)
function fnv1a64(str) {
  let h = BigInt('0xcbf29ce484222325'); // offset basis
  const p = BigInt('0x100000001b3');    // prime
  for (let i = 0; i < str.length; i++) {
    h ^= BigInt(str.charCodeAt(i));
    h = (h * p) & BigInt('0xFFFFFFFFFFFFFFFF');
  }
  let hex = h.toString(16);
  return hex.padStart(16, '0');
}

function stripDangerous(html) {
  if (!html) return '';
  let out = String(html);

  // Remove <script>…</script>
  out = out.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

  // Remove on*="..." handlers
  out = out.replace(/\son[a-z]+\s*=\s*(['"]).*?\1/gi, '');

  // Neutralize javascript: in href/src
  out = out.replace(/\s(href|src)\s*=\s*(['"])\s*javascript:[^'"]*\2/gi, ' $1="#"');

  // Sanitize inline styles: drop expression() and url(javascript:...)
  out = out.replace(/\sstyle\s*=\s*(['"])(?:(?!\1).)*\1/gi, (m) => {
    const val = m.replace(/^style\s*=\s*(['"])/i, '').replace(/['"]$/, '');
    const safe = val
      .replace(/expression\s*\([^)]*\)/gi, '')
      .replace(/url\(\s*['"]?\s*javascript:[^)]+?\)/gi, 'url(#)');
    return ` style="${safe}"`;
  });

  // Remove iframes (allowlist later if needed)
  out = out.replace(/<iframe\b[^>]*>([\s\S]*?)<\/iframe>/gi, '');

  return out;
}

function ensureHtmlShell(bodyInner, headTitle = 'Analysis Report') {
  const title = headTitle || 'Analysis Report';
  const head = `
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1">
    <title>${title}</title>
  `.trim();

  return [
    '<!DOCTYPE html>',
    '<html lang="en">',
    '<head>',
    head,
    '</head>',
    '<body>',
    bodyInner || '',
    '</body>',
    '</html>',
  ].join('\n');
}

