// n8n Function node — Universal Assistant JSON Parser
// Handles various OpenAI/Assistant API response formats
// Supports: GPT responses, Claude responses, direct JSON, code fences, etc.
//
// OUTPUT (default): One item with { subject_company_confirmation, competitors, _meta }
// Set SPLIT_COMPETITORS = true to emit one item per competitor

const SPLIT_COMPETITORS = false;

// ---------- helpers ----------
function firstTruthy(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return undefined;
}

function stripCodeFences(s) {
  if (typeof s !== "string") return s;
  // Handle ```json, ```JSON, or plain ```
  const patterns = [
    /```(?:json|JSON)?\s*([\s\S]*?)```/g,
    /~~~(?:json|JSON)?\s*([\s\S]*?)~~~/g
  ];

  for (const pattern of patterns) {
    const matches = [...s.matchAll(pattern)];
    if (matches.length > 0) {
      // Return the last match (most likely to be the complete one)
      return matches[matches.length - 1][1].trim();
    }
  }
  return s;
}

function extractJsonSlice(s) {
  if (typeof s !== "string") return s;

  // Find the outermost complete JSON object or array
  const braceStart = s.indexOf("{");
  const braceEnd = s.lastIndexOf("}");
  const arrStart = s.indexOf("[");
  const arrEnd = s.lastIndexOf("]");

  let cand = null;

  // Prefer object over array if both present
  if (braceStart !== -1 && braceEnd !== -1 && braceEnd > braceStart) {
    cand = s.slice(braceStart, braceEnd + 1);
  } else if (arrStart !== -1 && arrEnd !== -1 && arrEnd > arrStart) {
    cand = s.slice(arrStart, arrEnd + 1);
  }

  return cand || s;
}

function safeJsonParse(x) {
  // Already an object?
  if (x && typeof x === "object" && !Array.isArray(x)) {
    return x;
  }

  // Already an array?
  if (Array.isArray(x)) return x;

  let s = String(x ?? "").trim();
  if (!s) return null;

  // Remove code fences
  s = stripCodeFences(s).trim();

  // Try direct parse
  try { 
    return JSON.parse(s); 
  } catch (e) {
    // Silent fail, continue trying
  }

  // Try extracting the main JSON structure
  const slice = extractJsonSlice(s);
  if (slice && slice !== s) {
    try { 
      return JSON.parse(slice); 
    } catch (e) {
      // Silent fail
    }
  }

  // Handle double-encoded JSON: "\"{...}\""
  if ((s.startsWith('"') && s.endsWith('"')) || (s.startsWith("'") && s.endsWith("'"))) {
    const unq = s.slice(1, -1)
      .replace(/\\"/g, '"')
      .replace(/\\n/g, '\n')
      .replace(/\\t/g, '\t')
      .replace(/\\r/g, '\r')
      .replace(/\\\\/g, '\\');

    try { 
      return JSON.parse(unq); 
    } catch (e) {
      // Silent fail
    }

    const unqSlice = extractJsonSlice(unq);
    try { 
      return JSON.parse(unqSlice); 
    } catch (e) {
      // Silent fail
    }
  }

  return null;
}

function normUrl(u) {
  if (!u) return null;
