function coerceArray(x) {
  // If it's already an array, keep it
  if (Array.isArray(x)) return x;

  // If it's a string, try to JSON.parse; if it's JSON array, return it, else wrap as single
  if (typeof x === 'string') {
    try {
      const parsed = JSON.parse(x);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      // not JSON, just wrap the raw string
      return [x];
    }
  }

  // If it's an object, look for a nested array in common keys
  if (x && typeof x === 'object') {
    for (const k of ['items', 'data', 'payload', 'raw_posts', 'value']) {
      if (Array.isArray(x[k])) return x[k];
    }
    return [x]; // single object
  }

  // null/undefined/other primitives
  return [];
}

